var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"헬로우! 코핀 컴퍼니!","JPN":"ハロー！　コフィンカンパニー！","ENG":"Hello, Coffin Company!","TWN":"你們好！科芬公司！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"우선 맥스웰 코퍼레이션의 <color=#ffd34c>제 3연구단지 실험자원 회수</color> 작전에 참여해주신 태스크포스 전투원 분들을 진심으로 환영합니다.","JPN":"まずはマックスウェルコーポレーションの<color=#ffd34c>第3研究団地実験資源回収</color>作戦にご参加いただいたタスクフォースカンパニーの戦闘員の皆様を心より歓迎いたします。","ENG":"Maxwell Corporation is sincerely grateful toward all TASKFORCE combatants who decided to participate in the <color=#ffd34c>Third Research Complex Data Retrieval</color> operation.","TWN":"首先，歡迎各位特遣勢力戰鬥要員參與麥克斯韋爾企業的<color=#ffd34c>第三研究園區實驗資源回收</color>作戰。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"잘 아시겠지만, 저희 맥스웰 사는 카운터 분들을 위한 CRF증폭장비를 제조하는 곳으로 유명한 기업이랍니다.","JPN":"すでにご存知かと思いますが、我がマックスウェル社はカウンターのためのCRF増幅装置の製造で有名な企業です。","ENG":"As you may know, Maxwell Corporation is renowned for our production of CRF amplifiers for Counters.","TWN":"我想各位應該很清楚，我們麥克斯韋爾企業是一家為各位制裁者提供CRF增幅裝備的知名企業。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그런데 일주일 전, 본사의 연구단지 세 곳에서 불미스러운 폭발사고가 일어나는 바람에 귀중한 실험자원이 소실되고 말았지 뭡니까!","JPN":"ところが1週間前、本社の研究団地の3カ所で爆発事故という不祥事が起きたせいで貴重な実験資源が消失してしまったのです！","ENG":"But a week ago, three very unfortunate explosions within our research complex burnt all our valuable experimental assets to ashes!","TWN":"但是一周前，由於總公司的研究院區處發生了不光彩的爆炸事件，導致重要的實驗資源消失！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"설상가상으로 사고현장에선 CSE 3레벨의 급성침식현상이 일어났다고 하더군요.","JPN":"さらに事故現場ではCSEレベル3の急性侵食現象が発生したそうです。","ENG":"What is worse, there has been reports of an acute case of Level 3 Counterside effect sighted at the scene.","TWN":"雪上加霜的是，事故現場還發生了CSE等級3級的急性侵蝕現象。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 기존에 회수 작전에 참여했던 용병들이 귀환하지 못하고 작전지점에서 실종된 상황입니다.","JPN":"そのため回収作戦に参加していた傭兵たちが帰還できず、作戦地点で行方不明になった状況です。","ENG":"The mercenaries that were previously dispatched all went missing at the area of operation.","TWN":"所以先前參與回收作戰的傭兵都沒能返回，消失在了作戰地點的狀況。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"침식학 전문가들의 소견에 따르면 침식전 대비가 제대로 되어있지 않은 참여인원들이 정신적 착란상태에 빠져있을 가능성이 높다고 합니다.","JPN":"侵食学の専門家の所見によると、侵食戦にしっかりと備えていなかった参加者が精神的に錯乱状態に陥っている可能性が高いとのことです。","ENG":"According to Corruption experts, those that went in without anti-Corruption gear are highly likely to be suffering from various mental disorders.","TWN":"根據侵蝕學專家的意見，因為參與人員沒能做好應對侵蝕戰的準備，所以他們很有可能精神處於混亂狀態。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"쉽게 말해...... 미쳐버린 선발대가 여러분을 침식체로 오인하고 쏠 수도 있다는 얘기죠.","JPN":"簡単にご説明すると……狂った先発隊が皆様を侵食体と勘違いして誤射する可能性もあるということです。","ENG":"Simply put, the mercenaries may confuse you with Corrupted Objects and open fire at you.","TWN":"簡單來說……就是發瘋的先遣部隊有可能會把各位當成侵蝕體進行攻擊。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까...... 실종인원을 발견하실 경우 재량에 따라 인도적 구조를 행할 수도 있겠지만......","JPN":"ですので……行方不明者を発見された際に、裁量によって人道的救助を行うこともできますが……","ENG":"So... Use discretion if you run into them. You could do it in a humane way and try rescuing them,","TWN":"所以……如果各位發現失蹤者，可以根據個人情況進行人道主義救援，不過……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"전략상 불가피할 경우 사살을 하더라도 정당방위로 인정될 거라는 점...... 참고하여 잘 판단하시기 바랍니다.","JPN":"戦略上やむを得ない場合、射殺をしても正当防衛として認められるという点も……ご参考の上、判断してください。","ENG":"but even if things unfold in an unfavorable way and you get forced to harm them, you won't be held responsible.","TWN":"就算戰略上不可避免地將他們射殺，也會被認為是正當防禦……希望大家參考這一點好好進行判斷。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"카운터도 아닌 일개 용병이 작전 중에 죽는 경우는...... 뭐, 아주 흔한 일이니까요.","JPN":"カウンターでもない一介の傭兵が作戦中に死亡するのは......まぁ、よくあることですから。","ENG":"Well, they're regular mercenaries, and mercenaries get killed in action all the time, don't they?","TWN":"畢竟他們也不是制裁者，一介傭兵死於作戰……嗯，算是司空見慣的事呢。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"아 참. 작전지역에 입장하는 비 카운터 전투원들은 이터니움 실드를 필히 지참해야 합니다.","JPN":"ちなみに、作戦地域に突入する非カウンター戦闘員は、必ずエタニウムシールドを持参しなければなりません。","ENG":"Oh, one more thing. Any non-Counter combatants to enter the area of operation must bring an Eternium shield with them.","TWN":"啊，對了。請進入作戰區域的非制裁者戰鬥員務必攜帶永恆之金護盾。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"말씀을 드렸다시피, 작전지역은 지금 침식지대나 다름없는 상태니까요.","JPN":"申し上げたとおり、現在の作戦地域は侵食地帯と変わらない状態ですから。","ENG":"Like I told you, you're practically heading into the middle of the Corrupted Area.","TWN":"畢竟如我方才所言，作戰區域現在與侵蝕地帶沒什麼兩樣。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"아아, 하지만 이터니움 실드가 부족하더라도 걱정하지 마십시오.","JPN":"ああ、もしエタニウムシールドが足りなくても心配は要りません。","ENG":"Don't worry if you don't have an Eternium shield!","TWN":"啊，不過就算永恆之金護盾不夠也請不用擔心。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"작전 참여자에 한해 저희 본사측에서 이터니움 실드 제품을 15%할인된 특별가에 제공하기로 했으니까. 적극적인 이용 바랍니다.","JPN":"作戦参加者に限り、弊社のエタニウムシールド製品を15％割引した特別価格で提供しておりますので、ぜひご利用ください。","ENG":"For combatants in this operation only, Maxwell Corporation is offering a 15% discount for our Eternium shields! A chance like this doesn't come around very often!","TWN":"因為總公司決定，僅限於作戰參與者，我們將以八五折特價提供永恆之金盾牌產品。望大家積極利用這一優惠。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"......별 건 아니지만, 작전도중 사망 시 할인가가 적용된 제품은 환불이 불가능하단 점 참고하시길.","JPN":"……補足ですが、作戦中に死亡した場合、割引価格が適用された製品の払い戻しはできませんのでご了承ください。","ENG":"A little side note: in case of death, products purchased at a discounted price cannot be refunded.","TWN":"……也不是什麼特別的事，只是希望大家知道，如果在作戰中死亡，用優惠價買下的商品是不能退貨的。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};